-- ESTUDIAR · Fase E-2 (INGLÉS) — teoría de sesión + ejemplos con audio + prueba.
-- Llena el hueco que dejó E-1 en la estructura tab→nivel→tema→teoría. Contenido
-- autorado por profesores nativos + guardas deterministas + revisión adversarial.
-- SOLO inglés (course en). NO toca motor FSRS, economía, gating, certificación
-- ni los otros 5 idiomas. El quiz es FORMATIVO: califica con el grader tolerante
-- (jz_grade, mig 177) y NO paga XP/oro ni escribe user_item_attempts.

create table if not exists public.study_theory (
  id uuid primary key default gen_random_uuid(),
  course_id uuid not null references public.courses(id) on delete cascade,
  unit_order int not null,
  cefr_level text not null,
  title text not null,
  summary text not null,
  sections jsonb not null default '[]'::jsonb,
  examples jsonb not null default '[]'::jsonb,
  pitfalls jsonb not null default '[]'::jsonb,
  quiz jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (course_id, unit_order)
);

-- RLS ON sin política: el quiz lleva las respuestas → SOLO lo leen las funciones
-- SECURITY DEFINER de abajo (mismo patrón que lesson_vocab/stories.questions).
alter table public.study_theory enable row level security;
revoke all on public.study_theory from anon, authenticated;


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 1, 'A1', 'Ciao y piacere', 'Aprende a saludar según la hora y la confianza, a conjugar el verbo essere y a presentarte con «Mi chiamo…» y «Piacere!». También verás cuándo tratar de tú y cuándo de Lei.', '[{"heading": "Saludar: ciao, buongiorno, buonasera, arrivederci", "body": "El saludo cambia según la hora y la confianza. «Ciao» sirve para hola y para adiós, pero solo entre amigos o en familia. Con alguien que no conoces di «buongiorno» por la mañana o «buonasera» desde la tarde. Para despedirte con respeto: «arrivederci».", "bullets": ["Ciao = hola y adiós, solo con amigos o familia.", "Buongiorno por la mañana; buonasera desde la tarde.", "Arrivederci: despedida educada, sirve con cualquier persona."]}, {"heading": "El verbo essere (ser/estar)", "body": "Essere es irregular: hay que memorizarlo. En italiano el pronombre suele omitirse, porque la terminación ya dice quién habla. Por eso «Sono italiano» ya significa «soy italiano», sin necesidad de decir «io».", "bullets": ["io sono · tu sei · lui/lei è", "noi siamo · voi siete · loro sono", "«È» lleva acento; sin acento, «e» significa «y».", "El pronombre se omite casi siempre: «Siamo studenti»."]}, {"heading": "Presentarse: «Mi chiamo…», «Piacere!» y el trato con Lei", "body": "Di tu nombre con «Mi chiamo Ana» o «Sono Ana». Al conocer a alguien se responde «Piacere!». Para tu origen: «Sono di Lima». Con un desconocido trata de Lei y pon el verbo en tercera persona.", "bullets": ["«Come ti chiami?» (tú) frente a «Come si chiama?» (usted).", "Con Lei el verbo va en tercera persona: «Lei è italiana?».", "«Sono di + ciudad» para decir de dónde eres."]}]'::jsonb, '[{"it": "Ciao! Mi chiamo Ana. Piacere!", "es": "¡Hola! Me llamo Ana. ¡Encantada!", "text": "Ciao! Mi chiamo Ana. Piacere!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f7b2a5af-61bc-5556-ab3f-fa121f3be151.mp3"}, {"it": "Buongiorno, signor Rossi. Lei è il nuovo professore?", "es": "Buenos días, señor Rossi. ¿Usted es el nuevo profesor?", "text": "Buongiorno, signor Rossi. Lei è il nuovo professore?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1f3bb6df-8048-56dd-afef-16008e8b6a64.mp3"}, {"it": "Io sono di Lima e lui è di Bogotá.", "es": "Yo soy de Lima y él es de Bogotá.", "text": "Io sono di Lima e lui è di Bogotá.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d90675ee-2167-5489-bdce-ad1fd8b38669.mp3"}, {"it": "Noi siamo studenti d''italiano. Arrivederci, professoressa!", "es": "Nosotros somos estudiantes de italiano. ¡Adiós, profesora!", "text": "Noi siamo studenti d''italiano. Arrivederci, professoressa!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2e975219-3abe-5aa9-be55-50bc94fc46d5.mp3"}]'::jsonb, '[{"title": "«Ciao» no vale con un desconocido", "body": "En español «hola» sirve con todo el mundo, pero «ciao» es solo informal. Al camarero, al profesor o al entrar en una tienda se dice «buongiorno» o «buonasera»; ahí «ciao» suena demasiado familiar."}, {"title": "«Soy de Lima» es «Sono di Lima», no «sono da Lima»", "body": "El hispanohablante calca el «de» como «da». Con essere se usa DI: «Sono di Lima». Si prefieres el verbo venire, entonces sí va da: «Vengo da Lima». Lo que no existe es «sono da Lima»."}, {"title": "«Piacere!» aquí no es un verbo", "body": "«Piacere» funciona como fórmula fija al conocer a alguien: «encantado / encantada». No cambia según el género ni se conjuga, Solo, no significa «por favor»; con preposición sí: «per piacere» = «per favore»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Entras por la mañana en una panadería y saludas a una señora que no conoces. ¿Qué dices?", "options": ["Buongiorno", "Ciao", "Arrivederci"], "answer": "Buongiorno", "id": "u1q1"}, {"type": "cloze", "prompt": "Completa con la forma correcta del verbo essere (nosotros).", "text": "Noi ___ studenti.", "answer": "siamo", "accepted": ["siamo"], "id": "u1q2"}, {"type": "cloze", "prompt": "Completa con la forma correcta del verbo essere (yo).", "text": "Io ___ di Lima.", "answer": "sono", "accepted": ["sono"], "id": "u1q3"}, {"type": "multiple_choice", "prompt": "Hablas con la señora Rossi, a quien no conoces. ¿Cómo le preguntas su nombre?", "options": ["Come si chiama?", "Come ti chiami?", "Chi sei?"], "answer": "Come si chiama?", "id": "u1q4"}, {"type": "multiple_choice", "prompt": "¿Para qué se usa «Piacere!» en italiano?", "options": ["Para decir «encantado» al conocer a alguien", "Para pedir algo por favor", "Para despedirse por la noche"], "answer": "Para decir «encantado» al conocer a alguien", "id": "u1q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 2, 'A1', 'Números, edad y de dónde vienes', 'Aprende a contar hasta 100, a decir tu edad con el verbo avere (igual que el español) y a explicar de qué ciudad o país vienes.', '[{"heading": "Los números hasta 100", "body": "Del 1 al 20 se aprenden de memoria: uno, due, tre, quattro, cinque, sei, sette, otto, nove, dieci... hasta venti. A partir de venti se suma la unidad detrás: ventidue, trentasei, novantotto. Las decenas son venti, trenta, quaranta, cinquanta, sessanta, settanta, ottanta, novanta, cento.", "bullets": ["Se escriben en una sola palabra: quarantatré, cinquantuno.", "Ante uno y otto, la decena pierde su vocal final.", "Así: venti + uno = ventuno; trenta + otto = trentotto.", "Cento pierde la o ante otto (centotto) y se apostrofa: cent''anni."]}, {"heading": "La edad se dice con AVERE", "body": "Aquí el español te ayuda: en italiano la edad se dice con avere, igual que nosotros decimos «tengo». Nunca se usa essere. La fórmula es avere + número + anni.", "bullets": ["Ho trenta anni. Hai vent''anni? Lui ha quaranta anni.", "La palabra anni no se omite nunca.", "Para preguntar: Quanti anni hai?", "Ante anni, venti y cento se apostrofan: vent''anni, cent''anni."]}, {"heading": "De dónde vienes y dónde vives", "body": "Para el origen hay tres estructuras distintas. Con la ciudad de nacimiento se usa essere di. Con el punto de procedencia se usa venire da. Y para decir dónde vives se usa a con ciudades e in con países.", "bullets": ["Sono di Lima. Vengo dal Perù. Abito a Roma.", "Abito in Italia, in Spagna, in Messico (países).", "Da + il se contrae en dal: Vengo dal Cile.", "El español usa «en» para ambos; el italiano distingue a e in."]}]'::jsonb, '[{"it": "Ho venticinque anni e sono di Buenos Aires.", "es": "Tengo veinticinco años y soy de Buenos Aires.", "text": "Ho venticinque anni e sono di Buenos Aires.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8763882d-2422-5330-aea1-ea604fe06170.mp3"}, {"it": "Quanti anni hai? Ho vent''anni.", "es": "¿Cuántos años tienes? Tengo veinte años.", "text": "Quanti anni hai? Ho vent''anni.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b1e520a6-5334-55d2-a8ae-e96fe63a6023.mp3"}, {"it": "Vengo dalla Colombia, ma abito a Milano.", "es": "Vengo de Colombia, pero vivo en Milán.", "text": "Vengo dalla Colombia, ma abito a Milano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6f40e8e7-72ae-5c37-b1e5-fac2f554db03.mp3"}, {"it": "Mia madre ha cinquantatré anni e abita in Italia.", "es": "Mi madre tiene cincuenta y tres años y vive en Italia.", "text": "Mia madre ha cinquantatré anni e abita in Italia.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/096d8040-0809-5c90-a8b0-3a4f19db8104.mp3"}]'::jsonb, '[{"title": "«Sono venti anni» no existe", "body": "Aunque en otros idiomas la edad se diga con «ser», en italiano se dice con avere, igual que en español. Se dice Ho venti anni, nunca Sono venti anni. Y jamás se omite la palabra anni."}, {"title": "Ciudad con «a», país con «in»", "body": "El español dice «en» para las dos cosas: vivo en Roma, vivo en Italia. El italiano las separa: Abito a Roma (ciudad), Abito in Italia (país). Confundirlas es el error número uno del hispanohablante."}, {"title": "«di» dice origen, «da» dice procedencia", "body": "Sono di Napoli significa que naciste allí. Vengo da Napoli significa que llegas de ahí ahora. Con essere se usa di; con venire se usa da, que además se contrae con el artículo del país: dal Perù, dalla Francia."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «Tengo veinte años» en italiano?", "options": ["Ho vent''anni.", "Sono vent''anni.", "Sto vent''anni."], "answer": "Ho vent''anni.", "id": "u2q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta? (vivir EN una ciudad)", "options": ["Abito a Milano.", "Abito in Milano.", "Abito al Milano."], "answer": "Abito a Milano.", "id": "u2q2"}, {"type": "cloze", "prompt": "Completa con la preposición correcta. España es un país.", "text": "Abito ___ Spagna.", "answer": "in", "accepted": ["in"], "id": "u2q3"}, {"type": "cloze", "prompt": "Completa con la preposición correcta. Con el verbo essere se indica la ciudad de origen.", "text": "Sono ___ Roma.", "answer": "di", "accepted": ["di"], "id": "u2q4"}, {"type": "multiple_choice", "prompt": "¿Cómo se escribe el número 38 en italiano?", "options": ["trentotto", "trentaotto", "trentaddotto"], "answer": "trentotto", "id": "u2q5"}]'::jsonb)
