insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 3, 'A1', 'La familia', 'Aprende a nombrar a tu familia en italiano con su artículo y a usar los posesivos mio, mia, miei, mie. En italiano el posesivo casi siempre va con artículo: «il mio libro».', '[{"heading": "La familia, cada palabra con su artículo", "body": "En italiano cada sustantivo lleva su artículo: masculino «il», femenino «la». Aprende la palabra junto al artículo, como una sola pieza. En plural, «il» pasa a «i» y «la» pasa a «le».", "bullets": ["il padre, il fratello, il nonno, il figlio", "la madre, la sorella, la nonna, la figlia", "Plural: i fratelli, i nonni, le sorelle, le figlie"]}, {"heading": "Mio, mia, miei, mie llevan artículo", "body": "El posesivo tiene dos partes: la raíz (mio, tuo, suo) la elige QUIEN posee y la terminación concuerda con LO POSEÍDO. Y, a diferencia del español, normalmente va precedido de artículo: no basta con «mio», hace falta «il mio».", "bullets": ["il mio libro (masculino singular)", "la mia casa (femenino singular)", "i miei libri (masculino plural)", "le mie case (femenino plural)"]}, {"heading": "La excepción: parentesco en singular", "body": "Con los nombres de parentesco en singular (padre, madre, fratello, sorella, nonno, nonna, figlio, figlia) el posesivo va SIN artículo. En plural vuelve el artículo, siempre.", "bullets": ["Singular sin artículo: mio padre, mia sorella", "Plural con artículo: i miei fratelli, le mie sorelle", "«I miei genitori» = mis padres (los dos)"]}]'::jsonb, '[{"it": "Mio padre lavora a Milano.", "es": "Mi padre trabaja en Milán.", "text": "Mio padre lavora a Milano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5d7497e3-4d56-5550-838a-b3e46fb2c882.mp3"}, {"it": "Mia sorella si chiama Laura.", "es": "Mi hermana se llama Laura.", "text": "Mia sorella si chiama Laura.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/72b61280-6d67-54a2-b86a-86924f4d2bf7.mp3"}, {"it": "I miei genitori vivono a Roma.", "es": "Mis padres viven en Roma.", "text": "I miei genitori vivono a Roma.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9791d291-0240-586f-abce-27696ef5fb43.mp3"}, {"it": "Il mio libro è sul tavolo.", "es": "Mi libro está sobre la mesa.", "text": "Il mio libro è sul tavolo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/072ec8fd-acba-52e1-b82d-96eb19a8b5c4.mp3"}]'::jsonb, '[{"title": "«Mio libro» ✗ → «il mio libro» ✓", "body": "En español decimos «mi libro», sin artículo, y por eso sale solo *«mio libro». En italiano el posesivo pide artículo delante: il mio libro, la mia casa, i miei amici, le mie chiavi."}, {"title": "«Il mio padre» ✗ → «mio padre» ✓", "body": "Al aprender la regla anterior, muchos ponen artículo también con la familia. Con padre, madre, fratello, sorella, nonno, nonna en SINGULAR no se pone: mio padre, mia madre. Pero en plural sí: i miei fratelli, le mie nonne."}, {"title": "«I genitori» son los PADRES, no los parientes", "body": "«I miei genitori» significa mi padre y mi madre. Los parientes (tíos, primos, etc.) son «i parenti». Decir «i miei parenti» cuando hablas de tus padres cambia por completo el significado."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «Mi padre trabaja en Milán»?", "options": ["Mio padre lavora a Milano.", "Il mio padre lavora a Milano.", "Mio il padre lavora a Milano."], "answer": "Mio padre lavora a Milano.", "id": "u3q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «Mi libro es nuevo»?", "options": ["Il mio libro è nuovo.", "Mio libro è nuovo.", "Mia libro è nuovo."], "answer": "Il mio libro è nuovo.", "id": "u3q2"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «Mis hermanos viven en Roma»?", "options": ["I miei fratelli vivono a Roma.", "Miei fratelli vivono a Roma.", "Mio fratelli vivono a Roma."], "answer": "I miei fratelli vivono a Roma.", "id": "u3q3"}, {"type": "cloze", "prompt": "Completa con el artículo correcto (il / la).", "text": "___ madre di Marco è italiana.", "answer": "la", "accepted": ["la"], "id": "u3q4"}, {"type": "cloze", "prompt": "Completa con la palabra italiana para «padres» (padre y madre).", "text": "I miei ___ si chiamano Anna e Paolo.", "answer": "genitori", "accepted": ["genitori"], "id": "u3q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 4, 'A1', 'Comida y el bar', 'Aprende a pedir en un bar italiano con «Vorrei…» y a elegir el artículo determinado correcto (il, lo, l'', la / i, gli, le), la regla que el español no tiene.', '[{"heading": "Pedir en el bar: Vorrei…", "body": "Para pedir con educación se usa Vorrei («quería»). También es muy normal Prendo un caffè o simplemente Un caffè, per favore. Se cierra con grazie. El camarero pregunta Prego? o Desidera? y responde Subito.", "bullets": ["Vorrei un cornetto, per favore. Grazie.", "Prendo un cappuccino e una spremuta.", "Voglio suena brusco: úsalo lo menos posible.", "Il conto, per favore. Quanto costa?"]}, {"heading": "El artículo determinado singular", "body": "El italiano elige el artículo por el sonido que viene detrás. Masculino: il ante consonante normal, lo ante s+consonante, z, ps o gn, y l'' ante vocal. Femenino: la ante consonante y l'' ante vocal.", "bullets": ["il caffè, il tè, il pane, il vino.", "lo zucchero, lo spuntino, lo gnocco.", "l''aperitivo, l''acqua, l''olio, l''aceto.", "la birra, la panna, la pasta, l''insalata."]}, {"heading": "El plural: i, gli, le", "body": "Cada artículo tiene su plural. il se vuelve i; lo y el l'' masculino se vuelven gli; la y el l'' femenino se vuelven le. Por eso se dice gli spaghetti pero i panini.", "bullets": ["i caffè, i panini, i dolci.", "gli spaghetti, gli gnocchi, gli aperitivi.", "le birre, le paste, le insalate.", "El femenino nunca usa gli."]}]'::jsonb, '[{"it": "Vorrei un caffè e un cornetto, per favore.", "es": "Quería un café y un cruasán, por favor.", "text": "Vorrei un caffè e un cornetto, per favore.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/382782f4-c592-59f7-8cba-c03d56498a4c.mp3"}, {"it": "Lo zucchero è sul tavolo, vicino al latte.", "es": "El azúcar está en la mesa, cerca de la leche.", "text": "Lo zucchero è sul tavolo, vicino al latte.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/400dfb2d-158b-555b-be9b-35281940e355.mp3"}, {"it": "Prendo gli spaghetti e un bicchiere d''acqua.", "es": "Tomo los espaguetis y un vaso de agua.", "text": "Prendo gli spaghetti e un bicchiere d''acqua.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6ce6987d-97ad-5779-8035-fa8972e42ead.mp3"}, {"it": "Il burro e la panna sono nel frigorifero.", "es": "La mantequilla y la nata están en la nevera.", "text": "Il burro e la panna sono nel frigorifero.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7500f109-1c67-567d-b436-ce9487e0ff85.mp3"}]'::jsonb, '[{"title": "«Il burro» es la mantequilla", "body": "En italiano il burro significa mantequilla; el animal es l''asino. Un panino con il burro es un bocadillo con mantequilla. Ojo también con la panna, que es la nata: el pan es il pane."}, {"title": "«L''aceto» es el vinagre", "body": "L''aceto no es el aceite: el aceite es l''olio. Se dice l''olio d''oliva para la ensalada y l''aceto balsamico para el vinagre. Pedir aceto pensando en aceite arruina el plato."}, {"title": "«Il zucchero» no existe", "body": "Ante s+consonante, z, ps o gn el masculino pide lo, no il: lo zucchero, lo spuntino, lo studente. El español no distingue, por eso el hispanohablante dice il zucchero. En plural esos mismos nombres llevan gli."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "En una receta italiana lees «il burro». ¿Qué significa?", "options": ["la mantequilla", "el burro, el animal", "el vinagre"], "answer": "la mantequilla", "id": "u4q1"}, {"type": "multiple_choice", "prompt": "Quieres pedir aceite para la ensalada. ¿Cuál es la frase correcta?", "options": ["Vorrei l''olio, per favore.", "Vorrei l''aceto, per favore.", "Vorrei il burro, per favore."], "answer": "Vorrei l''olio, per favore.", "id": "u4q2"}, {"type": "cloze", "prompt": "Completa con el artículo determinado masculino singular. La palabra zucchero empieza por z.", "text": "Vorrei ___ zucchero, per favore.", "answer": "lo", "accepted": ["lo"], "id": "u4q3"}, {"type": "cloze", "prompt": "Completa con el artículo determinado masculino plural. En singular se dice lo spaghetto.", "text": "Prendo ___ spaghetti.", "answer": "gli", "accepted": ["gli"], "id": "u4q4"}, {"type": "cloze", "prompt": "Completa con el artículo determinado masculino singular. La palabra pane empieza por p.", "text": "Vorrei ___ pane, per favore.", "answer": "il", "accepted": ["il"], "id": "u4q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 5, 'A1', 'El día y la hora', 'Aprende a decir la hora en italiano (sono le tre, pero è l''una) y los días de la semana, con la diferencia entre «lunedì» y «il lunedì».', '[{"heading": "La hora: el español ayuda, pero la una rompe el patrón", "body": "Para dar la hora se usa «sono le» + número: Sono le tre, igual que el español «son las tres». Pero la una, el mediodía y la medianoche van en singular: È l''una, È mezzogiorno, È mezzanotte.", "bullets": ["Sono le due, sono le nove: plural, con «le».", "È l''una, è mezzogiorno, è mezzanotte: singular, con «è».", "El artículo es femenino porque se refiere a «le ore»."]}, {"heading": "Los minutos", "body": "Los minutos se añaden con «e»: sono le tre e dieci. El cuarto y la media tienen forma propia: e un quarto, e mezza. Para restar minutos se usa «meno»: sono le tre meno un quarto.", "bullets": ["Sono le otto e un quarto = son las ocho y cuarto.", "Sono le otto e mezza = son las ocho y media.", "Sono le nove meno un quarto = las nueve menos cuarto."]}, {"heading": "Los días de la semana", "body": "Son: lunedì, martedì, mercoledì, giovedì, venerdì, sabato, domenica. Los cinco primeros llevan acento en la última sílaba; sabato y domenica, no. Con artículo, «il lunedì» significa todos los lunes; sin artículo, «lunedì» es este lunes.", "bullets": ["lunedì, martedì, mercoledì, giovedì, venerdì llevan acento final.", "Lunedì vado a Roma = este lunes voy a Roma.", "Il lunedì vado in palestra = todos los lunes.", "Domenica es femenina: la domenica dormo di più."]}]'::jsonb, '[{"it": "Sono le tre e mezza.", "es": "Son las tres y media.", "text": "Sono le tre e mezza.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4981b0cd-f232-5a13-b6f2-199e98070270.mp3"}, {"it": "È l''una in punto.", "es": "Es la una en punto.", "text": "È l''una in punto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/70d5208e-920b-5fbc-a22a-56c82a83db2c.mp3"}, {"it": "Il lunedì vado in palestra.", "es": "Todos los lunes voy al gimnasio.", "text": "Il lunedì vado in palestra.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/75be2dc0-604a-55f9-801b-6f7199294fbb.mp3"}, {"it": "Domenica non lavoro.", "es": "Este domingo no trabajo.", "text": "Domenica non lavoro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/eccdc6cd-1851-5bd7-9de3-035c61026294.mp3"}]'::jsonb, '[{"title": "«È l''una», nunca «sono le una»", "body": "El hispanohablante traduce «son las» para todas las horas y dice *sono le una. La una es una sola hora, así que el italiano usa el singular: È l''una. Lo mismo con È mezzogiorno y È mezzanotte. De las dos en adelante, siempre «sono le»."}, {"title": "Los días se escriben con minúscula", "body": "En italiano los días van en minúscula dentro de la frase, igual que en español: «Ci vediamo lunedì», no *Lunedì. Solo llevan mayúscula al empezar la oración. Ojo si vienes del inglés (Monday), donde sí se escriben con mayúscula."}, {"title": "El acento final: lunedì, no *lunedi", "body": "Cinco días terminan en «-dì» con acento escrito obligatorio: lunedì, martedì, mercoledì, giovedì, venerdì. Escribirlos sin acento es una falta de ortografía. Sabato y domenica no llevan acento escrito: SÀ-ba-to en la primera sílaba, do-MÉ-ni-ca en la segunda."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cómo se dice «Son las tres»?", "options": ["Sono le tre", "Sono la tre", "È le tre"], "answer": "Sono le tre", "id": "u5q1"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «Es la una»?", "options": ["È l''una", "Sono le una", "Sono l''una"], "answer": "È l''una", "id": "u5q2"}, {"type": "multiple_choice", "prompt": "¿Cuál frase significa «todos los sábados juego al fútbol»?", "options": ["Il sabato gioco a calcio", "Sabato gioco a calcio", "Un sabato gioco a calcio"], "answer": "Il sabato gioco a calcio", "id": "u5q3"}, {"type": "multiple_choice", "prompt": "«Son las ocho menos cuarto». ¿Cuál es la forma italiana?", "options": ["Sono le otto meno un quarto.", "Sono le otto meno quarto.", "Sono le sette e quarantacinque meno."], "answer": "Sono le otto meno un quarto.", "id": "u5q4"}, {"type": "cloze", "prompt": "Escribe el artículo que falta. Significa: «Son las cuatro y media».", "text": "Sono ___ quattro e mezza.", "answer": "le", "accepted": ["le"], "id": "u5q5"}]'::jsonb)
