insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 7, 'A2', 'El pasado: lo que hice', 'Aprende el passato prossimo con avere: el pasado que el italiano usa para contar lo que hiciste ayer. Incluye los participios regulares y los irregulares más frecuentes.', '[{"heading": "Cómo se forma: avere + participio", "body": "El passato prossimo se forma con el presente de avere más el participio del verbo. Es el pasado normal para contar lo que hiciste ayer, el fin de semana o esta mañana.", "bullets": ["Presente de avere: ho, hai, ha, abbiamo, avete, hanno.", "Ho parlato, hai dormito, abbiamo capito: solo cambia avere.", "Algunos verbos de movimiento usan essere: eso se ve aparte."]}, {"heading": "Participios regulares: -ato, -uto, -ito", "body": "Para formar el participio regular cambia la terminación del infinitivo: los verbos en -are hacen -ato, los de -ere hacen -uto y los de -ire hacen -ito. La raíz no se toca.", "bullets": ["parlare → parlato; mangiare → mangiato; comprare → comprato.", "credere → creduto; avere → avuto; ricevere → ricevuto.", "dormire → dormito; capire → capito; finire → finito."]}, {"heading": "Irregulares que hay que memorizar", "body": "Muchos verbos muy usados tienen participio irregular y no siguen ninguna regla: se aprenden de memoria. Son justo los que más necesitas para contar tu día.", "bullets": ["fare → fatto; dire → detto; leggere → letto.", "prendere → preso; vedere → visto; scrivere → scritto.", "bere → bevuto: irregular en la raíz, pero termina en -uto."]}]'::jsonb, '[{"it": "Ieri ho mangiato al ristorante.", "es": "Ayer comí en el restaurante.", "text": "Ieri ho mangiato al ristorante.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6c610df9-eb7f-5d53-8682-95a6b827ef12.mp3"}, {"it": "Maria ha letto un libro interessante.", "es": "María leyó un libro interesante.", "text": "Maria ha letto un libro interessante.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9e89f4ef-6a1f-5436-a089-1e6dafa01147.mp3"}, {"it": "Abbiamo visto un film ieri sera.", "es": "Vimos una película ayer por la noche.", "text": "Abbiamo visto un film ieri sera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/07e880dd-d19b-5333-8b11-db6856563219.mp3"}, {"it": "Che cosa hai fatto domenica?", "es": "¿Qué hiciste el domingo?", "text": "Che cosa hai fatto domenica?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/804617cf-052f-5cdf-b39f-63a6f0b23278.mp3"}]'::jsonb, '[{"title": "«Ieri ho mangiato» = «ayer comí»", "body": "En español reservas «he comido» para lo muy reciente y dices «comí» para ayer. El italiano usa el passato prossimo en los dos casos: «Ieri ho mangiato», «Stamattina ho mangiato». No busques otra forma: esta es la del día a día."}, {"title": "Con avere el participio no concuerda", "body": "El participio termina en -o, aunque el sujeto sea femenino o plural: «Lei ha mangiato», «Loro hanno mangiato». Decir «lei ha mangiata» sale de trasladar a «avere» la concordancia de «essere» (è andata). Solo con essere hay concordancia, y eso se ve en otro tema."}, {"title": "Los irregulares no se deducen", "body": "«Leggere» no hace *legguto* ni «prendere» *prenduto»: hacen letto y preso. No intentes aplicarles la regla de -uto: son formas que se memorizan una a una, como las de fare (fatto) o dire (detto)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál es el participio del verbo «leggere»?", "options": ["letto", "leggiuto", "leggeto"], "answer": "letto", "id": "u7q1"}, {"type": "cloze", "prompt": "Completa con el participio del verbo «mangiare».", "text": "Ieri ho ___ una pizza con Marco.", "answer": "mangiato", "accepted": ["mangiato"], "id": "u7q2"}, {"type": "multiple_choice", "prompt": "«Ayer comí en casa». ¿Cómo se dice en italiano?", "options": ["Ieri ho mangiato a casa.", "Ieri mangio a casa.", "Ieri sono mangiato a casa."], "answer": "Ieri ho mangiato a casa.", "id": "u7q3"}, {"type": "cloze", "prompt": "Completa con el participio del verbo «prendere».", "text": "Stamattina ho ___ il treno per Roma.", "answer": "preso", "accepted": ["preso"], "id": "u7q4"}, {"type": "multiple_choice", "prompt": "¿Cuál es el participio del verbo «scrivere»?", "options": ["scritto", "scrivuto", "scriveto"], "answer": "scritto", "id": "u7q5"}]'::jsonb)
