insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 8, 'A2', 'Planes y futuro', 'Aprende a hablar de planes en italiano con el futuro semplice, sus irregulares y «stare per + infinitivo». Verás por qué «vado a mangiare» NO es un plan futuro.', '[{"heading": "El futuro semplice: -erò para casi todos", "body": "Se forma sobre el infinitivo sin la -e final. Los verbos en -are cambian la a por e: parlare → parlerò. Los de -ere y -ire mantienen su vocal: prendere → prenderò, partire → partirò. Las terminaciones son iguales para los tres grupos. Dare, stare y fare conservan la a: darò, starò, farò.", "bullets": ["parlare → parlerò, parlerai, parlerà, parleremo, parlerete, parleranno", "prendere → prenderò · partire → partirò", "La -a- de -are pasa a -e-; -care/-gare añaden h: cercherò.", "La 1ª persona lleva acento escrito: parlerò"]}, {"heading": "Los irregulares pierden la vocal", "body": "Un grupo muy usado contrae la raíz: cae la vocal del infinitivo. Son pocos, pero son los verbos más frecuentes, así que conviene memorizarlos en bloque.", "bullets": ["essere → sarò · avere → avrò", "andare → andrò · fare → farò", "potere → potrò · dovere → dovrò · sapere → saprò", "venire → verrò · volere → vorrò (doble r)"]}, {"heading": "«Stare per» y el presente con valor de futuro", "body": "«Stare per + infinitivo» indica algo inmediato: está a punto de pasar. Y al hablar, para planes con fecha concreta, el italiano usa muchísimo el presente: es natural y correcto, no un error.", "bullets": ["Il treno sta per partire = está a punto de salir", "Domani parto alle otto (presente = plan futuro)", "Con marcador temporal, presente y futuro valen igual", "El futuro también expresa suposición: Sarà stanco"]}]'::jsonb, '[{"it": "Domani partirò per Roma con mia sorella.", "es": "Mañana saldré para Roma con mi hermana.", "text": "Domani partirò per Roma con mia sorella.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/21d85539-a465-5497-9e8a-026696073098.mp3"}, {"it": "Non so dove sono le chiavi: saranno in cucina.", "es": "No sé dónde están las llaves: estarán en la cocina.", "text": "Non so dove sono le chiavi: saranno in cucina.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ac8cece0-530a-5ef7-8136-77710319574e.mp3"}, {"it": "Sbrigati, il film sta per cominciare!", "es": "¡Date prisa, la película está a punto de empezar!", "text": "Sbrigati, il film sta per cominciare!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d1ed8ed9-7da0-5bc5-a158-4e90a65273b8.mp3"}, {"it": "Stasera mangio a casa di Luca, poi verrò da te.", "es": "Esta noche como en casa de Luca, luego iré a tu casa.", "text": "Stasera mangio a casa di Luca, poi verrò da te.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/84b98f06-1336-5477-8395-32e60882ac33.mp3"}]'::jsonb, '[{"title": "«Vado a mangiare» no significa «voy a comer» (plan)", "body": "El hispanohablante calca «voy a + infinitivo». En italiano «vado a mangiare» vale para lo inmediato («adesso vado a mangiare»), no para un plan con fecha. Para un plan futuro usa «mangerò» o el presente con marcador: «Domani mangio fuori». La perífrasis con andare no existe como futuro en italiano."}, {"title": "El acento de parlerò no se ve, pero se oye", "body": "La 1ª persona del futuro es tónica en la última sílaba y lleva acento escrito: parlerò, avrò, sarò. Sin acento (parlero) la palabra no existe en italiano. Escríbelo siempre, aunque el corrector de la app no te lo penalice."}, {"title": "«Verrò» y «vorrò» llevan doble r", "body": "Venire → verrò y volere → vorrò duplican la r; avere → avrò y andare → andrò no la duplican. Un solo error de r cambia la palabra: «verrò» (vendré) frente a «vero» (verdadero). Repásalos en bloque para no mezclarlos."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Tu amigo te pregunta qué planes tienes mañana. ¿Cuál de estas frases NO expresa un plan futuro en italiano?", "options": ["Vado a mangiare.", "Domani mangio con Anna.", "Domani mangerò con Anna."], "answer": "Vado a mangiare.", "id": "u8q1"}, {"type": "multiple_choice", "prompt": "Futuro semplice de ''venire'' en la 1ª persona (yo vendré). Elige la forma correcta:", "options": ["verrò", "venirò", "vengerò"], "answer": "verrò", "id": "u8q2"}, {"type": "multiple_choice", "prompt": "Completa con el irregular correcto: «Domani ___ in centro con Marco» (yo iré).", "options": ["andrò", "sarò", "farò"], "answer": "andrò", "id": "u8q3"}, {"type": "cloze", "prompt": "Escribe el futuro semplice de ''parlare'' en 1ª persona singular (yo hablaré).", "text": "Domani ___ con il direttore.", "answer": "parlerò", "accepted": ["parlerò", "parlero"], "id": "u8q4"}, {"type": "cloze", "prompt": "Completa la expresión de inmediatez con la preposición que acompaña a ''stare'' (algo está a punto de pasar).", "text": "Sbrigati! Il treno sta ___ partire.", "answer": "per", "accepted": ["per"], "id": "u8q5"}]'::jsonb)
