insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 9, 'A2', 'De viaje', 'Cuenta tu viaje en pasado: los verbos de movimiento usan ESSERE y su participio concuerda con el sujeto. Además, el vocabulario de la estación y los falsos amigos que más traicionan (salire, partire).', '[{"heading": "El passato prossimo con ESSERE", "body": "Los verbos de movimiento y de cambio de estado forman el passato prossimo con essere, no con avere: andare, venire, partire, arrivare, uscire, entrare, tornare, restare, nascere, morire. El auxiliar se conjuga (sono, sei, è, siamo, siete, sono) y detrás va el participio.", "bullets": ["sono andato, sei venuto, è partito, siamo usciti", "Ojo: viaggiare, camminare y nuotare van con AVERE (ho viaggiato in treno).", "Con avere van los verbos con complemento directo: ho mangiato la pizza."]}, {"heading": "Con essere el participio CONCUERDA", "body": "Con essere el participio cambia como un adjetivo: -o, -a, -i, -e, según quién es el sujeto. Con avere el participio queda fijo en -o: «Anna ha mangiato la pizza», nunca «Anna ha mangiata la pizza».", "bullets": ["lui è andato · lei è andata", "loro (chicos) sono andati · loro (chicas) sono andate", "Grupo mixto de hombres y mujeres: masculino plural, sono andati.", "Con avere no se toca: «lei ha visitato», «loro hanno visitato»."]}, {"heading": "Palabras de viaje que engañan", "body": "«Salire» significa SUBIR, no salir: «salgo sul treno» es «subo al tren». Para salir se usa «uscire» (de un lugar) o «partire» (marcharse de viaje). En la stazione, el «binario» es la vía por la que sale el tren, no un binario de tren.", "bullets": ["salire = subir · scendere = bajar", "uscire = salir de un sitio · partire = salir de viaje", "la stazione, il binario, il biglietto, la valigia", "Con complemento, salire y scendere usan avere: ho salito le scale."]}]'::jsonb, '[{"it": "Ieri sera sono arrivata a Roma alle nove.", "es": "Ayer por la noche llegué a Roma a las nueve. (habla una mujer)", "text": "Ieri sera sono arrivata a Roma alle nove.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/beb6d0f5-1308-55ff-9ef7-68a4bd20c469.mp3"}, {"it": "Marco e Luca sono partiti dalla stazione di Milano.", "es": "Marco y Luca salieron de la estación de Milán.", "text": "Marco e Luca sono partiti dalla stazione di Milano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/78d4e7b6-cb5c-51fc-b634-4f3853da13fe.mp3"}, {"it": "Siamo saliti sul treno al binario cinque.", "es": "Subimos al tren en el andén cinco.", "text": "Siamo saliti sul treno al binario cinque.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/802ae6c6-bfe0-56b3-938b-a34ea7713b79.mp3"}, {"it": "Abbiamo visitato il museo e poi siamo tornati in albergo.", "es": "Visitamos el museo y luego volvimos al hotel.", "text": "Abbiamo visitato il museo e poi siamo tornati in albergo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d7a01860-bc40-5d3d-a9cc-accf6ef38a66.mp3"}]'::jsonb, '[{"title": "«Ho andato» no existe", "body": "Es el error número uno del hispanohablante: traducir «he ido» por «ho andato». Los verbos de movimiento piden essere → «sono andato / sono andata». Lo mismo con sono partito, sono uscito, sono arrivato, sono tornato."}, {"title": "«Salire» es SUBIR, no salir", "body": "«Salgo sul treno» significa «subo al tren». Si quieres decir «salgo de casa», es «esco di casa» (uscire); si es «el tren sale a las nueve», es «il treno parte alle nove» (partire). Y para bajar del tren: «scendo dal treno»."}, {"title": "Con essere el participio no es fijo", "body": "«Lei è andato» está mal: si el sujeto es femenino, «lei è andata». Con dos chicas, «sono andate»; con dos chicos o grupo mixto, «sono andati». Con avere el participio queda en -o, salvo si delante va lo/la/li/le (l''ho vista), que verás más adelante: «lei ha dormito», «loro hanno dormito»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Maria (mujer, ella sola) cuenta su viaje. ¿Qué frase es correcta?", "options": ["Maria è andata a Milano in treno.", "Maria è andato a Milano in treno.", "Maria ha andata a Milano in treno."], "answer": "Maria è andata a Milano in treno.", "id": "u9q1"}, {"type": "multiple_choice", "prompt": "Marco y Luca son dos chicos. ¿Qué frase es correcta?", "options": ["Marco e Luca sono arrivati ieri sera.", "Marco e Luca sono arrivate ieri sera.", "Marco e Luca hanno arrivati ieri sera."], "answer": "Marco e Luca sono arrivati ieri sera.", "id": "u9q2"}, {"type": "cloze", "prompt": "Escribe el auxiliar del passato prossimo. (habla un hombre).", "text": "Ieri io ___ partito da Napoli alle otto.", "answer": "sono", "accepted": ["sono"], "id": "u9q3"}, {"type": "cloze", "prompt": "Escribe el auxiliar del passato prossimo de «visitare».", "text": "Ieri noi ___ visitato il Colosseo con Anna.", "answer": "abbiamo", "accepted": ["abbiamo"], "id": "u9q4"}, {"type": "multiple_choice", "prompt": "«Il treno parte alle nove e io scendo alla prossima fermata» significa:", "options": ["El tren sale a las nueve y yo bajo en la próxima parada.", "El tren sube a las nueve y yo salgo en la próxima parada.", "El tren se parte a las nueve y yo subo en la próxima parada."], "answer": "El tren sale a las nueve y yo bajo en la próxima parada.", "id": "u9q5"}]'::jsonb)
