insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 10, 'A2', 'Comer fuera y comprar', 'Aprende a comparar en italiano (più… di, meno… di, tanto… quanto) y a elegir entre «di» y «che». Con las palabras que necesitas en el restaurante y en la tienda.', '[{"heading": "Comparar: più, meno, tanto… quanto", "body": "El comparativo se forma con più (más) o meno (menos) delante del adjetivo. Para decir que dos cosas son iguales se usa tanto… quanto o così… come. El segundo término se introduce con di o con che, y ahí está toda la dificultad.", "bullets": ["Marco è più alto di Luca (más alto que Luca)", "Questo vino è meno caro di quello (menos caro)", "Anna è tanto simpatica quanto Marco (tan… como)"]}, {"heading": "«di» o «che»: la trampa del hispanohablante", "body": "Usa «di» cuando comparas dos personas o dos cosas: va delante de un nombre o de un pronombre. Usa «che» cuando comparas dos cualidades del mismo sujeto o dos verbos. El español dice siempre «que», por eso el error es tan frecuente.", "bullets": ["che + dos adjetivos: è più simpatico che intelligente", "che + dos verbos: è più facile leggere che scrivere", "che también ante preposición: più caro a Roma che a Milano", "Dos nombres del mismo verbo piden che: bevo più caffè che tè."]}, {"heading": "Irregulares y palabras de la mesa y la tienda", "body": "Buono, cattivo y grande tienen comparativos irregulares: migliore, peggiore, maggiore. Se usan sobre todo para la calidad y para la edad. En el restaurante y en la tienda te harán falta unas pocas palabras que salen en cada conversación.", "bullets": ["buono → migliore · cattivo → peggiore · grande → maggiore", "il cameriere (camarero) · il conto (la cuenta) · la mancia (la propina)", "Vorrei prenotare un tavolo per due, per favore", "En la tienda: Quanto costa? · Posso provarlo? · Lo prendo"]}]'::jsonb, '[{"it": "Vorrei prenotare un tavolo per due per sabato sera.", "es": "Quisiera reservar una mesa para dos para el sábado por la noche.", "text": "Vorrei prenotare un tavolo per due per sabato sera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a8c7ffa0-270b-51d9-a432-e36fbd5b8e52.mp3"}, {"it": "Cameriere, il conto per favore! La mancia non è obbligatoria.", "es": "¡Camarero, la cuenta por favor! La propina no es obligatoria.", "text": "Cameriere, il conto per favore! La mancia non è obbligatoria.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b76901e6-4fad-56f5-8ea7-ffbe1bac4540.mp3"}, {"it": "Questo vino è più caro di quello, ma è migliore.", "es": "Este vino es más caro que aquel, pero es mejor.", "text": "Questo vino è più caro di quello, ma è migliore.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/116abd19-8ed4-5465-a0ef-cf18c7e64583.mp3"}, {"it": "Questa borsa è più elegante che comoda, ma la compro.", "es": "Este bolso es más elegante que cómodo, pero lo compro.", "text": "Questa borsa è più elegante che comoda, ma la compro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3e5b668a-4ec1-5ffe-bc80-71cb5e725495.mp3"}]'::jsonb, '[{"title": "No todo «que» español se dice «di»", "body": "El español usa siempre «que»: más alto que yo, más simpático que inteligente. El italiano separa: «di» ante un nombre o un pronombre (più alto di me), «che» entre dos cualidades del mismo sujeto o dos verbos (più simpatico che intelligente). Pregúntate qué dos cosas estás comparando antes de escribir."}, {"title": "«Il conto» es la cuenta, «la mancia» es la propina", "body": "«Il conto» no es un cuento: es lo que pides al terminar de comer. «La mancia» no tiene nada que ver con una mancha: es la propina, y en Italia es voluntaria (muchos locales cobran ya «il coperto»). Y «il cameriere» es el camarero, no una cámara."}, {"title": "«Più buono» no es un error: es otro matiz", "body": "«Più buono» existe y es correcto cuando hablas de sabor: «Questa pizza è più buona di quella». «Migliore» apunta a la calidad general o a lo que no se come: «prezzi migliori», «il migliore ristorante». No los tomes como bien y mal, sino como dos matices distintos."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Quieres decir que una persona es más simpática que inteligente (comparas dos cualidades suyas). ¿Cuál es la frase correcta en italiano?", "options": ["È più simpatico che intelligente.", "È più simpatico di intelligente.", "È più simpatico come intelligente."], "answer": "È più simpatico che intelligente.", "id": "u10q1"}, {"type": "multiple_choice", "prompt": "Has terminado de comer y quieres pagar. ¿Qué le pides al cameriere?", "options": ["Il conto, per favore.", "La mancia, per favore.", "Il coperto, per favore."], "answer": "Il conto, per favore.", "id": "u10q2"}, {"type": "multiple_choice", "prompt": "En una tienda quieres decir que allí los precios son MEJORES (mejor calidad de oferta, no sabor). ¿Cuál eliges?", "options": ["Questo negozio ha prezzi migliori.", "Questo negozio ha prezzi più grandi.", "Questo negozio ha prezzi maggiori."], "answer": "Questo negozio ha prezzi migliori.", "id": "u10q3"}, {"type": "cloze", "prompt": "Aquí comparas a dos personas: Marco y yo. Escribe la palabra que introduce el segundo término.", "text": "Marco è più alto ___ me.", "answer": "di", "accepted": ["di"], "id": "u10q4"}, {"type": "cloze", "prompt": "Aquí comparas dos cualidades del MISMO restaurante (caro y elegante). Escribe la palabra que las une.", "text": "Questo ristorante è più caro ___ elegante.", "answer": "che", "accepted": ["che"], "id": "u10q5"}]'::jsonb)
