insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 11, 'A2', 'Personas y descripciones', 'Describe cómo era la gente y cómo eran las cosas con el imperfetto, y haz concordar el adjetivo con el sustantivo.', '[{"heading": "El imperfetto: el decorado del pasado", "body": "Como el imperfecto español: cómo era algo o qué hacías habitualmente. Quita -re del infinitivo y añade -vo, -vi, -va, -vamo, -vate, -vano: parlare → parlavo, prendere → prendevo, dormire → dormivo. Se usa para describir personas, lugares y costumbres.", "bullets": ["parlavo, parlavi, parlava, parlavamo, parlavate, parlavano", "La -v- está en todos los regulares; la excepción es essere (ero, eri, era).", "Funciona casi igual que el imperfecto español"]}, {"heading": "Essere y tres verbos que se acortan", "body": "Solo essere rompe el molde: ero, eri, era, eravamo, eravate, erano. Otros tres recuperan su raíz latina: fare → facevo, bere → bevevo, dire → dicevo. Avere es regular: avevo, avevi, aveva.", "bullets": ["essere: ero, eri, era, eravamo, eravate, erano", "fare → facevo · bere → bevevo · dire → dicevo", "avere es regular: avevo, aveva, avevano"]}, {"heading": "Imperfetto o passato prossimo", "body": "El imperfetto pinta el fondo (era, faceva, c''era gente); el passato prossimo cuenta lo que pasó de golpe. Y el adjetivo concuerda: alto, alta, alti, alte. Los adjetivos en -e (gentile, felice) no cambian de género, solo hacen plural en -i.", "bullets": ["Fondo: Era tardi. Acción: È arrivato Marco.", "alto / alta / alti / alte según el sustantivo", "gentile → gentili: mismo para él y para ella"]}]'::jsonb, '[{"it": "Quando ero piccolo, abitavo a Milano.", "es": "Cuando era pequeño, vivía en Milán.", "text": "Quando ero piccolo, abitavo a Milano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/978b80db-f3dd-55d5-bc78-cf383c239aaf.mp3"}, {"it": "Mia nonna era molto gentile e faceva sempre il dolce la domenica.", "es": "Mi abuela era muy amable y siempre hacía el postre el domingo.", "text": "Mia nonna era molto gentile e faceva sempre il dolce la domenica.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b4467749-b0f2-50d5-8cf7-24c22372ec55.mp3"}, {"it": "Le mie sorelle erano alte e avevano i capelli neri.", "es": "Mis hermanas eran altas y tenían el pelo negro.", "text": "Le mie sorelle erano alte e avevano i capelli neri.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2fded1e1-89e2-5461-87a9-3e98d83397da.mp3"}, {"it": "Dormivo quando è arrivato tuo fratello.", "es": "Estaba durmiendo cuando llegó tu hermano.", "text": "Dormivo quando è arrivato tuo fratello.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/07abf79a-f535-5738-9ba1-b9cb89c1efef.mp3"}]'::jsonb, '[{"title": "«Imbarazzata» NO es embarazada", "body": "«Sono imbarazzata» significa «estoy avergonzada». Embarazada se dice «incinta»: «Mia sorella è incinta». Decir «sono imbarazzata» en el hospital provoca justo lo que la palabra significa."}, {"title": "El adjetivo no puede quedarse en masculino", "body": "En italiano el adjetivo concuerda siempre: «Marta era stanca», «I bambini erano stanchi», «Le ragazze erano stanche». Un «Marta era stanco» suena tan mal como en español."}, {"title": "Simpatico y sensibile", "body": "«Sensibile» sí es sensible (buena noticia). Pero «simpatico» es más amplio que simpático: se usa para alguien agradable, gracioso, con el que se está a gusto. Su contrario, «antipatico», es de uso diario."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta del imperfetto de essere: «Da bambini, noi ___ sempre insieme.»", "options": ["eravamo", "siamo stati", "eravate"], "answer": "eravamo", "id": "u11q1"}, {"type": "multiple_choice", "prompt": "«Mi hermana está embarazada» en italiano es:", "options": ["Mia sorella è incinta", "Mia sorella è imbarazzata", "Mia sorella è imbarazzante"], "answer": "Mia sorella è incinta", "id": "u11q2"}, {"type": "cloze", "prompt": "Imperfetto de FARE. Completa: «Da giovane mio padre ___ il cuoco.» (él hacía de cocinero, habitualmente)", "text": "Da giovane mio padre ___ il cuoco.", "answer": "faceva", "accepted": ["faceva"], "id": "u11q3"}, {"type": "cloze", "prompt": "Concordancia del adjetivo. El sujeto es «Le mie amiche» (femenino plural). Completa con ALTO: «Le mie amiche erano molto ___.»", "text": "Le mie amiche erano molto ___.", "answer": "alte", "accepted": ["alte"], "id": "u11q4"}, {"type": "multiple_choice", "prompt": "Fondo en imperfetto, acción en passato prossimo. Elige la frase correcta:", "options": ["Pioveva quando siamo usciti di casa.", "Pioveva quando abbiamo uscito di casa.", "Pioveva quando eravamo usciti di casa."], "answer": "Pioveva quando siamo usciti di casa.", "id": "u11q5"}]'::jsonb)
