insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 12, 'A2', 'Salud, cuerpo y consejos', 'Aprende a decir qué te duele con «mi fa male / mi fanno male» y con «ho mal di…», y a dar consejos con «dovresti + infinitivo».', '[{"heading": "Mi fa male / mi fanno male", "body": "En italiano el dolor se expresa como en español: el sujeto es la parte del cuerpo, no la persona. Por eso el verbo concuerda con ella: «mi fa male» con singular y «mi fanno male» con plural. «Mi» indica a quién le duele.", "bullets": ["Singular: «Mi fa male la schiena» (me duele la espalda).", "Plural: «Mi fanno male le gambe, i denti, gli occhi».", "Cambia la persona: «ti fa male», «gli fanno male»."]}, {"heading": "La fórmula fija «ho mal di…»", "body": "«Ho mal di + parte» es una fórmula fija: sin artículo y con «mal» apocopado. Es tan correcta y frecuente como «mi fa male la testa»: las dos se usan a diario. Se ve sobre todo con testa, gola, stomaco, denti, schiena, orecchi.", "bullets": ["«Ho mal di testa / di gola / di stomaco».", "«Ho male di gola» no; sí «ho male alla gola».", "Para otras partes: «mi fa male il ginocchio»."]}, {"heading": "Aconsejar: dovresti, devi", "body": "Para aconsejar usa «dovresti + infinitivo» (condicional de dovere): suena amable, como «deberías». «Devi + infinitivo» es más directo, como «tienes que». También funciona «perché non + presente?»: «Perché non vai dal medico?».", "bullets": ["«Dovresti riposare», «dovresti bere molta acqua».", "«Devi prendere la medicina»: obligación, más fuerte.", "Trato formal: «dovrebbe andare dal medico»."]}]'::jsonb, '[{"it": "Mi fa male la testa da stamattina.", "es": "Me duele la cabeza desde esta mañana.", "text": "Mi fa male la testa da stamattina.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4cd5b231-ae8f-51be-8c4e-9098269068eb.mp3"}, {"it": "Mi fanno male i piedi: ho camminato troppo.", "es": "Me duelen los pies: he caminado demasiado.", "text": "Mi fanno male i piedi: ho camminato troppo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5f1c9e7f-899f-558f-904c-61a64df0901d.mp3"}, {"it": "Ho mal di gola e un po'' di febbre.", "es": "Tengo dolor de garganta y un poco de fiebre.", "text": "Ho mal di gola e un po'' di febbre.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/285a535c-eb41-5c24-9e7c-2af5d135508d.mp3"}, {"it": "Dovresti riposare e bere molta acqua.", "es": "Deberías descansar y beber mucha agua.", "text": "Dovresti riposare e bere molta acqua.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3bf9f2f6-fa2a-5583-b4aa-899abb65d19a.mp3"}]'::jsonb, '[{"title": "¿«fa» o «fanno»? Manda la parte del cuerpo", "body": "El verbo concuerda con lo que duele, no contigo. Con «le gambe» o «i denti» (plural) se dice «mi fanno male», no «mi fa male». Es el mismo mecanismo que «me gusta / me gustan» en español."}, {"title": "«mal» sin artículo, «male» con el verbo", "body": "En la fórmula fija se apocopa: «ho mal di stomaco», sin artículo. Con el verbo fare se usa la forma entera: «mi fa male lo stomaco». Las dos frases son correctas; lo que no se dice es «ho male di stomaco»."}, {"title": "«costipato» no es «estreñido»", "body": "En italiano «costipato» y «la costipazione» suelen referirse al resfriado con la nariz tapada. Para «estreñido» se dice «stitico» (y «la stitichezza»). Si dices «sono costipato» en la farmacia, entenderán que estás resfriado."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Mi ___ male lo stomaco.»", "options": ["fa", "fanno", "fai"], "answer": "fa", "id": "u12q1"}, {"type": "cloze", "prompt": "Completa con el verbo. Fíjate: la parte del cuerpo está en plural.", "text": "Dopo la partita, mi ___ male le gambe.", "answer": "fanno", "accepted": ["fanno"], "id": "u12q2"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases es correcta en italiano?", "options": ["Ho mal di gola.", "Ho male di gola.", "Ho mal della gola."], "answer": "Ho mal di gola.", "id": "u12q3"}, {"type": "cloze", "prompt": "Da un consejo con el condicional de «dovere» (el equivalente de «deberías»). Escribe solo el verbo.", "text": "Hai la febbre: ___ andare dal medico.", "answer": "dovresti", "accepted": ["dovresti"], "id": "u12q4"}, {"type": "multiple_choice", "prompt": "En Italia, «Sono costipato» se entiende normalmente como…", "options": ["Estoy resfriado, con la nariz tapada.", "Estoy estreñido.", "Estoy muy cansado."], "answer": "Estoy resfriado, con la nariz tapada.", "id": "u12q5"}]'::jsonb)
