  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 13, 'B1', 'Opinión y deseo: el congiuntivo presente', 'Sabrás formar el congiuntivo presente (parli, prenda, finisca, sia, vada) y usarlo tras «penso che», «voglio che» o «benché», sin calcar el español.', '[{"heading": "Cómo se forma el congiuntivo presente", "body": "El congiuntivo presente se forma con la vocal contraria: los verbos en -are toman -i (parli), y los de -ere e -ire toman -a (prenda, dorma). Las tres personas del singular son idénticas, por eso casi siempre se dice el pronombre: che tu parli.", "bullets": ["«parlare» → parli; «prendere» → prenda; «dormire» → dorma.", "Verbos en -isc-: «finire» → finisca; «capire» → capisca.", "Plural: noi -iamo, voi -iate, loro -ino (parlino) o -ano (prendano).", "io, tu, lui/lei comparten forma: usa el pronombre para aclarar."]}, {"heading": "Los irregulares más frecuentes", "body": "Los irregulares más usados hay que aprenderlos de memoria: essere → sia, avere → abbia, potere → possa. Muchos otros salen de la primera persona del presente: vado → vada, vengo → venga, faccio → faccia, dico → dica. En el singular todos estos irregulares acaban en -a.", "bullets": ["essere → sia; avere → abbia; potere → possa; dovere → debba.", "andare → vada; venire → venga; fare → faccia; dire → dica.", "Truco: muchos nacen del «io» del presente (vengo → venga).", "essere y avere no siguen el truco: memoriza sia y abbia."]}, {"heading": "Cuándo lo pide el italiano (y el español no)", "body": "El congiuntivo depende de lo que va delante. Lo piden la opinión y la duda (penso che, credo che, mi sembra che), la voluntad (voglio che, spero che) y los impersonales (è importante che, bisogna che). También conjunciones como benché, prima che o a meno che.", "bullets": ["Opinión y duda: «Penso che», «Credo che», «Mi sembra che».", "Voluntad: «Voglio che», «Spero che», «Preferisco che venga».", "Conjunciones: «benché», «sebbene», «prima che», «a meno che».", "Certeza → indicativo: «So che viene», «È vero che viene»."]}]'::jsonb, '[{"it": "Penso che Marco abbia ragione.", "es": "Creo que Marco tiene razón.", "text": "Penso che Marco abbia ragione.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/191ee3f4-6dba-5bc0-869a-a58a3d0b3af6.mp3"}, {"it": "Voglio che tu mi dica la verità.", "es": "Quiero que me digas la verdad.", "text": "Voglio che tu mi dica la verità.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/02ffdc60-4445-5851-a62a-8e01e97777be.mp3"}, {"it": "Benché sia stanca, esce con gli amici.", "es": "Aunque está cansada, sale con los amigos.", "text": "Benché sia stanca, esce con gli amici.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/55309b95-4d19-58a3-a01e-6fd55501ef9a.mp3"}, {"it": "È meglio che tu prenda il treno delle otto.", "es": "Es mejor que tomes el tren de las ocho.", "text": "È meglio che tu prenda il treno delle otto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e31308ee-a0c5-50e7-8644-af842c7b70f5.mp3"}]'::jsonb, '[{"title": "«Penso che viene» es el calco más frecuente", "body": "En español dices «Creo que viene» con indicativo, y el calco directo «Penso che viene» suena mal en italiano. Después de penso, credo, mi sembra o spero, el verbo va en congiuntivo: «Penso che venga». Es el error número uno del hispanohablante."}, {"title": "No te pases: «so che» va con indicativo", "body": "Cuidado con pasarse de congiuntivo: los verbos de certeza piden indicativo. Se dice «So che è a casa» y «È vero che viene», no «so che sia». Si afirmas un hecho seguro, usa el indicativo; el congiuntivo llega cuando opinas, dudas o deseas."}, {"title": "«che lui parli», nunca «che lui parla»", "body": "Las tres personas del singular comparten forma (io, tu, lui parli), por eso se suele decir el pronombre. Donde se falla es en la tercera: el indicativo «lui parla» se cuela tras «Voglio che». Di «Voglio che lui parli»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Creo que viene pronto» se dice en italiano…", "options": ["Penso che venga presto.", "Penso che viene presto.", "Penso che venire presto."], "answer": "Penso che venga presto.", "id": "u13q1"}, {"type": "cloze", "prompt": "Completa con el congiuntivo presente del verbo «parlare».", "text": "Voglio che Marco ___ con il direttore domani.", "answer": "parli", "accepted": ["parli"], "id": "u13q2"}, {"type": "multiple_choice", "prompt": "Solo una de estas frases es correcta. ¿Cuál?", "options": ["So che Luca è a Roma.", "So che Luca sia a Roma.", "Penso che Luca è a Roma."], "answer": "So che Luca è a Roma.", "id": "u13q3"}, {"type": "cloze", "prompt": "Completa con el congiuntivo presente del verbo «andare».", "text": "Spero che ___ tutto bene con il nuovo lavoro.", "answer": "vada", "accepted": ["vada"], "id": "u13q4"}, {"type": "cloze", "prompt": "Completa con el congiuntivo presente de «finire», del grupo que añade -isc-.", "text": "È importante che tu ___ il lavoro entro venerdì.", "answer": "finisca", "accepted": ["finisca"], "id": "u13q5"}]'::jsonb)
