insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 14, 'B1', 'Futuro, condicional e hipótesis', 'Sabrás hablar del futuro, pedir y aconsejar con el condicional (vorrei, potresti, dovrebbe) y formar hipótesis reales con «se» + presente de indicativo.', '[{"heading": "Futuro y condicional comparten la raíz", "body": "El condicional se construye sobre la misma raíz que el futuro: cambia solo la terminación. Si sabes «parlerò», ya sabes «parlerei»; si sabes «sarò», ya sabes «sarei». Los irregulares del futuro se repiten idénticos en el condicional, así que se estudian juntos.", "bullets": ["Futuro: parlerò, prenderò, partirò, sobre el infinitivo sin la -e final.", "Raíces irregulares: essere→sarò/sarei, avere→avrò/avrei, andare→andrò/andrei.", "Contraídos: potere→potrei, dovere→dovrei, volere→vorrei, venire→verrei.", "Los -are cambian la a: parlare→parlerei; salvo dare, stare y fare."]}, {"heading": "Condizionale presente: -ei, -esti, -ebbe", "body": "Las terminaciones son iguales para los tres grupos: -ei, -esti, -ebbe, -emmo, -este, -ebbero. Equivale al «-ría» español: parlerei = hablaría. Sirve para pedir con cortesía, aconsejar, expresar un deseo y suavizar una opinión sin sonar tajante.", "bullets": ["parlare: parlerei, parleresti, parlerebbe, parleremmo, parlereste, parlerebbero.", "Cortesía: «Vorrei un caffè», «Mi passeresti il sale, per favore?».", "Consejo: «Dovresti riposare»; con usted, «Dovrebbe parlare con il medico».", "Deseo y opinión: «Mi piacerebbe vederti», «Sarebbe meglio partire presto»."]}, {"heading": "«Se» + presente: la hipótesis real", "body": "Para una condición que sí puede cumplirse, el italiano usa «se» + indicativo, igual que el español: «Se piove, resto a casa». En la principal caben presente, futuro o imperativo. Y ojo: a diferencia del español, tras «se» el italiano admite también el futuro.", "bullets": ["«Se piove, resto a casa»: presente + presente, como en español.", "«Se avrò tempo, ti chiamerò»: en italiano el futuro tras «se» es correcto.", "Con imperativo en la principal: «Se hai fame, mangia qualcosa».", "«se» = si (condición); «sì» con acento = sí (afirmación)."]}]'::jsonb, '[{"it": "Se ho tempo, passo da te dopo cena.", "es": "Si tengo tiempo, paso por tu casa después de cenar.", "text": "Se ho tempo, passo da te dopo cena.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/cc4d6b97-0ce1-5859-9679-b55271f0f1d9.mp3"}, {"it": "Vorrei un tavolo per due, per favore.", "es": "Querría una mesa para dos, por favor.", "text": "Vorrei un tavolo per due, per favore.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/6247c2a1-c2f2-5ff5-9271-a9603ca396ae.mp3"}, {"it": "Secondo me dovresti parlarne con il tuo capo.", "es": "En mi opinión deberías hablarlo con tu jefe.", "text": "Secondo me dovresti parlarne con il tuo capo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f0972786-f76e-5744-ba45-c37a559d9612.mp3"}, {"it": "Domani sarò a Roma e ti scriverò appena arrivo.", "es": "Mañana estaré en Roma y te escribiré en cuanto llegue.", "text": "Domani sarò a Roma e ti scriverò appena arrivo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b0270d0e-a697-5028-85f7-f30050b1b9f8.mp3"}]'::jsonb, '[{"title": "Tras «se» de hipótesis real va indicativo", "body": "Si acabas de estudiar el congiuntivo, es fácil pasarse: la «se» de condición real pide indicativo. Di «Se piove, resto a casa», no «Se piova». Y tampoco condicional: «Se pioverebbe» es incorrecto, igual que «si llovería» en español."}, {"title": "«parleremo» (futuro) ≠ «parleremmo» (condicional)", "body": "La única diferencia entre el futuro y el condicional de «nosotros» es la doble m: «parleremo» es hablaremos y «parleremmo» es hablaríamos. Lo mismo con andremo/andremmo y saremo/saremmo. Pronuncia la m larga: en italiano la doble se oye y cambia el significado."}, {"title": "«Voglio un caffè» suena brusco", "body": "Pedir con «voglio» es correcto gramaticalmente, pero en un bar o una tienda suena exigente. Los italianos usan el condicional: «Vorrei un caffè, per favore». Con «potresti» o «potrebbe» pides un favor sin sonar imperativo: «Potrebbe ripetere, per favore?»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Nos quedaríamos un día más» — elige la forma correcta:", "options": ["Resteremmo un altro giorno.", "Resteremo un altro giorno.", "Resterebbero un altro giorno."], "answer": "Resteremmo un altro giorno.", "id": "u14q1"}, {"type": "cloze", "prompt": "Pide algo con cortesía en un bar: escribe el condicional presente de «volere» en 1ª persona (yo). Solo el verbo.", "text": "Buongiorno, ___ un caffè macchiato, per favore.", "answer": "vorrei", "accepted": ["vorrei"], "id": "u14q2"}, {"type": "cloze", "prompt": "Hipótesis real con «se». Conjuga «uscire» en 2ª persona (tú).", "text": "Se ___ presto dal lavoro, ti aspetto al bar.", "answer": "esci", "accepted": ["esci"], "id": "u14q3"}, {"type": "multiple_choice", "prompt": "«Yo debería llamarla esta tarde» — elige la forma correcta:", "options": ["dovrei chiamarla", "doverei chiamarla", "dovrò chiamarla"], "answer": "dovrei chiamarla", "id": "u14q4"}, {"type": "cloze", "prompt": "Pide un favor con cortesía: condicional presente de «potere» en 2ª persona (tú). Solo el verbo.", "text": "___ aprire la finestra, per favore?", "answer": "potresti", "accepted": ["potresti"], "id": "u14q5"}]'::jsonb)
