insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 15, 'B1', 'Relativos: che, cui, il cui, chi, dove', 'Sabrás enlazar frases con «che», usar «cui» detrás de preposición, decir «cuyo» con «il cui» y distinguir «chi» y «dove».', '[{"heading": "«Che»: el relativo comodín, invariable", "body": "«Che» es el relativo más frecuente: vale para el sujeto, «il libro che è sul tavolo», y para el objeto directo, «il libro che leggo». No cambia nunca: sirve con masculino, femenino, singular y plural. Lo que no hace es ir detrás de una preposición.", "bullets": ["Sujeto: «La ragazza che canta è mia sorella».", "Objeto directo: «Il film che abbiamo visto era noioso».", "Invariable: vale para masculino y femenino, singular y plural.", "Detrás de preposición no vale: «in che», «con che» son errores."]}, {"heading": "«Cui» tras preposición y «il cui» = cuyo", "body": "Detrás de una preposición el italiano usa «cui», no «che»: «la casa in cui vivo», «l''amico a cui scrivo», «il tema di cui parliamo». «Cui» también es invariable. Con el artículo delante, «il cui» o «la cui», significa «cuyo» y concuerda con la cosa poseída.", "bullets": ["Bloque fijo: in cui, a cui, di cui, con cui, su cui.", "«Il negozio in cui lavoro» (negozio = tienda, no negocio).", "Posesivo: «l''autrice il cui libro ho comprato» (su libro).", "«Il cui» concuerda con lo poseído, no con el poseedor."]}, {"heading": "«Chi», «dove» y el formal «il quale»", "body": "«Chi» significa «quien» y va sin antecedente: «Chi dorme non piglia pesci». El verbo que lo acompaña va en singular. Para el lugar puedes usar «dove», que equivale a «in cui»: «il paese dove sono nato». «Il quale / la quale» es la variante formal.", "bullets": ["«Chi» no necesita antecedente: «Ammiro chi dice la verità».", "El verbo con «chi» va en singular: «Chi arriva tardi paga».", "Lugar: «la città dove abito» = «la città in cui abito».", "Formal: «il progetto del quale parliamo», más frecuente escrito."]}]'::jsonb, '[{"it": "Il ragazzo che parla con Marta è mio fratello.", "es": "El chico que habla con Marta es mi hermano.", "text": "Il ragazzo che parla con Marta è mio fratello.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ee485eeb-5766-5399-bb78-887552d2a2e7.mp3"}, {"it": "Questa è la casa in cui sono cresciuto.", "es": "Esta es la casa en la que crecí.", "text": "Questa è la casa in cui sono cresciuto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8a7da937-5b22-5d84-bbbe-4aedfbba5c38.mp3"}, {"it": "Lo scrittore il cui romanzo hai letto è siciliano.", "es": "El escritor cuya novela has leído es siciliano.", "text": "Lo scrittore il cui romanzo hai letto è siciliano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d24012b9-2023-5203-93b6-7d7b9834e342.mp3"}, {"it": "Chi arriva tardi aspetta fuori dal negozio.", "es": "Quien llega tarde espera fuera de la tienda.", "text": "Chi arriva tardi aspetta fuori dal negozio.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/39a5c1da-f38d-5d79-a232-a19dda54b71e.mp3"}]'::jsonb, '[{"title": "«in che» no existe: se dice «in cui»", "body": "En español decimos «la casa en la que vivo», y muchos calcan «la casa in che vivo». En italiano, detrás de cualquier preposición el relativo es «cui»: «in cui», «a cui», «di cui», «con cui»."}, {"title": "«chi» no traduce «que»: significa «quien»", "body": "«Chi» no sustituye a un nombre ya dicho: va solo, sin antecedente, como en «Chi tace acconsente». Por eso «la ragazza chi ho visto» es un error; se dice «la ragazza che ho visto»."}, {"title": "«cuyo» = «il cui», y concuerda con lo poseído", "body": "Para «cuyo» no valen «che il» ni «di cui il». Se dice «il cui»: el artículo concuerda con la cosa poseída, no con el dueño. «Lo scrittore la cui casa…» (casa, femenino), «l''attrice il cui film…»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Questo è il bar ___ faccio colazione ogni mattina.»", "options": ["in cui", "in che", "in quale"], "answer": "in cui", "id": "u15q1"}, {"type": "cloze", "prompt": "Completa el hueco. Recuerda: detrás de una preposición, «che» no vale.", "text": "Il libro di ___ ti ho parlato è in offerta.", "answer": "cui", "accepted": ["cui"], "id": "u15q2"}, {"type": "multiple_choice", "prompt": "¿Cómo se dice «El escritor cuyo libro ganó el premio»?", "options": ["Lo scrittore il cui libro ha vinto il premio.", "Lo scrittore che il libro ha vinto il premio.", "Lo scrittore di cui il libro ha vinto il premio."], "answer": "Lo scrittore il cui libro ha vinto il premio.", "id": "u15q3"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases es correcta en italiano?", "options": ["La ragazza che ho visto ieri è mia cugina.", "La ragazza cui ho visto ieri è mia cugina.", "La ragazza chi ho visto ieri è mia cugina."], "answer": "La ragazza che ho visto ieri è mia cugina.", "id": "u15q4"}, {"type": "cloze", "prompt": "Completa con el adverbio de lugar que puede sustituir a «in cui».", "text": "Il paese ___ sono nato è vicino a Firenze.", "answer": "dove", "accepted": ["dove", "in cui"], "id": "u15q5"}]'::jsonb)
