  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 16, 'B1', 'Concordancia del participio pasado', 'Sabrás cuándo el participio cambia de final: con essere concuerda con el sujeto, con avere solo si lo, la, li o le van delante, y los reflexivos piden essere.', '[{"heading": "Con essere: manda el sujeto", "body": "Un grupo cerrado de verbos —andare, venire, partire, uscire, arrivare, tornare, restare— forma el pasado con essere. Ahí el participio funciona como un adjetivo y copia el género y el número del sujeto: ‑o, ‑a, ‑i, ‑e. No entra cualquier verbo de movimiento: camminare y viaggiare van con avere.", "bullets": ["Marco è andato a Roma. / Maria è andata a Roma.", "I ragazzi sono usciti. / Le ragazze sono uscite.", "En español el participio nunca cambia: «ella ha salido».", "salire = SUBIR (bajar es scendere): «sono salita sul treno»."]}, {"heading": "Con avere: normalmente no cambia", "body": "Con avere el participio se queda invariable en ‑o: «Ho comprato le mele». Solo cambia si el complemento directo va DELANTE en forma de pronombre lo, la, li, le y «ne»: entonces el participio copia su género y su número. Con lo y la se apostrofan delante de ho.", "bullets": ["Li ho visti al bar. → «li» delante: visti.", "L''ho vista ieri. (la = Maria) → apóstrofo y ‑a.", "Ojo: «le ho parlato» (a ella) no concuerda: es indirecto.", "Con «ne» también concuerda: «Ne ho comprate tre»."]}, {"heading": "Los reflexivos van siempre con essere", "body": "Los verbos reflexivos —alzarsi, svegliarsi, lavarsi, divertirsi— usan essere, aunque en español digas «me he levantado» con haber. El participio concuerda con el sujeto. Y sigue concordando con el sujeto aunque detrás haya un objeto: «Si è lavata le mani».", "bullets": ["Mi sono alzata alle sei. (habla una mujer)", "Ci siamo divertiti molto alla festa.", "En español: «me he lavado»; en italiano, essere y no avere.", "Con objeto detrás sigue igual: «Si è lavata le mani»."]}]'::jsonb, '[{"it": "Maria è andata al cinema con le sue amiche.", "es": "María fue al cine con sus amigas.", "text": "Maria è andata al cinema con le sue amiche.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/676041a9-65c5-5d97-94f1-85dbea348372.mp3"}, {"it": "I ragazzi sono usciti presto e sono tornati tardi.", "es": "Los chicos salieron temprano y volvieron tarde.", "text": "I ragazzi sono usciti presto e sono tornati tardi.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/30e9c140-ede9-564f-9833-a22a46cb75f0.mp3"}, {"it": "Hai le foto? Sì, le ho viste ieri sera.", "es": "¿Tienes las fotos? Sí, las vi ayer por la noche.", "text": "Hai le foto? Sì, le ho viste ieri sera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7e09e62b-b598-5722-83c3-959beeb5b88d.mp3"}, {"it": "Stamattina mi sono svegliata tardi e ho perso il treno.", "es": "Esta mañana me desperté tarde y perdí el tren.", "text": "Stamattina mi sono svegliata tardi e ho perso il treno.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4d3a740d-84b0-52b9-9725-14c8a28fe4cd.mp3"}]'::jsonb, '[{"title": "«Ha andato» no existe: andare pide essere", "body": "En español todo se forma con haber, y por eso sale «ha andato». En italiano andare, venire, partire, uscire y tornare piden essere, y el participio concuerda con el sujeto: «Marta e Giulia sono andate», no «hanno andato»."}, {"title": "Con avere cambia con lo, la, li, le y «ne»", "body": "«Ho comprate le mele» está mal: cuando el complemento va detrás, el participio se queda en ‑o, «ho comprato». La concordancia aparece solo si ese objeto se adelanta como pronombre: «Le ho comprate al mercato»."}, {"title": "«Mi ho svegliato» no: el reflexivo pide essere", "body": "Como en español dices «me he despertado», sale «mi ho svegliato». En italiano el reflexivo va con essere y el participio concuerda contigo: una mujer dice «mi sono svegliata»; un hombre, «mi sono svegliato»."}]'::jsonb, '[{"type": "cloze", "prompt": "Completa con el participio de «partire». Fíjate en el sujeto: son dos mujeres.", "text": "Le mie sorelle sono ___ ieri sera.", "answer": "partite", "accepted": ["partite"], "id": "u16q1"}, {"type": "multiple_choice", "prompt": "¿Cuál de estas frases es correcta en italiano?", "options": ["Ho comprato le mele.", "Ho comprate le mele.", "Ho comprati le mele."], "answer": "Ho comprato le mele.", "id": "u16q2"}, {"type": "cloze", "prompt": "Aquí «le» sustituye a «le chiavi» (femenino plural) y va delante del verbo. Completa el participio.", "text": "Hai preso le chiavi? Sì, le ho ___ io.", "answer": "prese", "accepted": ["prese"], "id": "u16q3"}, {"type": "multiple_choice", "prompt": "Anna cuenta su fin de semana. ¿Cuál es la frase correcta?", "options": ["Mi sono divertita moltissimo.", "Mi ho divertita moltissimo.", "Mi sono divertito moltissimo."], "answer": "Mi sono divertita moltissimo.", "id": "u16q4"}, {"type": "cloze", "prompt": "Completa con el participio de «andare». Marta y Giulia son dos mujeres.", "text": "Ieri Marta e Giulia sono ___ a teatro.", "answer": "andate", "accepted": ["andate"], "id": "u16q5"}]'::jsonb)
