insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 20, 'B2', 'Periodo hipotético II y III + condicional pasado', 'Sabrás plantear hipótesis improbables e imposibles («Se avessi tempo, verrei») y usar el condizionale passato para el futuro en el pasado y el arrepentimiento.', '[{"heading": "Ipotesi possibile: se + congiuntivo imperfetto", "body": "Cuando la hipótesis es poco probable, el «se» lleva congiuntivo imperfetto y el resultado va en condizionale presente: «Se avessi tempo, verrei». Es el mismo esquema del español «si tuviera…, iría». Recuerda que la hipótesis real de la unidad 14 se construye con indicativo: «Se ho tempo, vengo».", "bullets": ["Congiuntivo imperfetto: avessi, fossi, potessi, sapessi, venissi, facessi.", "Resultado en condizionale presente: verrei, andrei, farei, direi.", "«Se fossi in te, non lo direi»: un consejo muy frecuente.", "En el «se» de condición no cabe condizionale: «se verrei» no existe."]}, {"heading": "Ipotesi impossibile: se avessi studiato…", "body": "Si la hipótesis ya no puede cumplirse porque pertenece al pasado, el «se» pide congiuntivo trapassato (avessi fatto, fossi andato) y el resultado va en condizionale passato (avrei detto, sarei venuto). Con essere el participio concuerda con el sujeto: «sarebbe arrivata».", "bullets": ["«Se avessi studiato, avrei superato l''esame».", "Congiuntivo trapassato: avessi fatto, fossi uscito, avessimo saputo.", "Condizionale passato: avrei detto, sarebbe venuta, saremmo partiti.", "Mixto frecuente: «Se fossi partito prima, ora sarei a casa»."]}, {"heading": "Condizionale passato: il futuro nel passato", "body": "Cuando cuentas en pasado algo que entonces era futuro, el italiano usa condizionale passato, no presente: «Ha detto che sarebbe venuto». El español dice «dijo que vendría», y ahí está la trampa. El condizionale passato sirve también para lamentar: «Avrei dovuto ascoltarti».", "bullets": ["«Pensavo che avrebbe telefonato»: futuro visto desde el pasado.", "Arrepentimiento: avrei dovuto, avrei potuto, avrei voluto dirtelo.", "Con movimiento también se oye «sarei dovuto andare»: ambas circulan.", "En prensa marca noticia no confirmada: «avrebbe firmato ieri»."]}]'::jsonb, '[{"it": "Se avessi tempo, verrei volentieri con voi.", "es": "Si tuviera tiempo, iría con mucho gusto con vosotros.", "text": "Se avessi tempo, verrei volentieri con voi.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e8e1a83b-cff4-5b34-85a1-9a182ac95be3.mp3"}, {"it": "Se avessi studiato di più, avrei superato l''esame.", "es": "Si hubiera estudiado más, habría aprobado el examen.", "text": "Se avessi studiato di più, avrei superato l''esame.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8205449d-bce6-5186-93e2-cb7485e3afe0.mp3"}, {"it": "Mi ha detto che sarebbe arrivato alle otto.", "es": "Me dijo que llegaría a las ocho.", "text": "Mi ha detto che sarebbe arrivato alle otto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/72c9f5df-5744-5915-bb22-ec597a0aaa3b.mp3"}, {"it": "Avrei dovuto chiamarti ieri sera, scusami.", "es": "Debería haberte llamado ayer por la noche, perdóname.", "text": "Avrei dovuto chiamarti ieri sera, scusami.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0d564122-e044-5aab-8367-37a17aea1fa6.mp3"}]'::jsonb, '[{"title": "«Ha detto che verrebbe» es el error estrella", "body": "El español traduce el futuro en el pasado con condicional simple: «dijo que vendría». El italiano necesita el condizionale passato: «Ha detto che sarebbe venuto». «Che verrebbe» no expresa ese futuro: un italiano dirá «sarebbe venuto»."}, {"title": "No repitas el congiuntivo en las dos mitades", "body": "En español se oye «si hubiera estudiado, hubiera aprobado», con dos subjuntivos. El italiano reparte: congiuntivo trapassato solo tras «se», y condizionale passato en el resultado. Di «Se avessi studiato, avrei superato l''esame», no «avessi superato»."}, {"title": "«Dovrei» no es «debería haber»", "body": "«Dovrei chiamare il medico» significa «debería llamar al médico» ahora. Para lamentar lo que no hiciste ayer necesitas el condizionale passato: «Avrei dovuto chiamare il medico». Lo mismo con potere y volere: «avrei potuto», «avrei voluto»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Me dijo que llegaría a las ocho». ¿Cómo se dice en italiano?", "options": ["Mi ha detto che sarebbe arrivato alle otto.", "Mi ha detto che arriverebbe alle otto.", "Mi ha detto che arriverà alle otto."], "answer": "Mi ha detto che sarebbe arrivato alle otto.", "id": "u20q1"}, {"type": "cloze", "prompt": "Completa con «avere» en la forma que pide el «se» de una hipótesis improbable. Una sola palabra.", "text": "Se ___ più tempo libero, verrei con voi in montagna.", "answer": "avessi", "accepted": ["avessi"], "id": "u20q2"}, {"type": "multiple_choice", "prompt": "«Si hubiera estudiado, habría aprobado el examen». Elige la traducción correcta.", "options": ["Se avessi studiato, avrei superato l''esame.", "Se avessi studiato, avessi superato l''esame.", "Se avrei studiato, avrei superato l''esame."], "answer": "Se avessi studiato, avrei superato l''esame.", "id": "u20q3"}, {"type": "cloze", "prompt": "Completa lamentando algo que no hiciste. Usa el condizionale passato de «dovere» (dos palabras).", "text": "Scusami, ___ chiamarti prima di partire.", "answer": "avrei dovuto", "accepted": ["avrei dovuto"], "id": "u20q4"}, {"type": "multiple_choice", "prompt": "Ayer no llamaste al médico y ahora te arrepientes. ¿Qué dices?", "options": ["Avrei dovuto chiamare il medico.", "Dovrei chiamare il medico.", "Avrei chiamato il medico."], "answer": "Avrei dovuto chiamare il medico.", "id": "u20q5"}]'::jsonb)
