insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000004', 23, 'B2', 'Conectores y conjunciones + congiuntivo', 'Sabrás qué conjunciones exigen congiuntivo (benché, purché, prima che) y cuáles piden indicativo (anche se, siccome), y enlazarás ideas con tuttavia o quindi.', '[{"heading": "Conjunciones que EXIGEN congiuntivo", "body": "Un grupo de conjunciones arrastra siempre el congiuntivo, sea real o no lo que dicen: manda la conjunción, no el sentido. Como las tres primeras personas del congiuntivo coinciden, se suele añadir el pronombre: «purché tu venga», «benché lui sia stanco».", "bullets": ["Concesión: benché, sebbene, nonostante, malgrado + congiuntivo.", "Condición: purché, a patto che, a condizione che, a meno che (non).", "Finalidad: affinché, perché con valor final. Ausencia: senza che.", "Anterioridad: prima che («prima che il negozio chiuda»)."]}, {"heading": "Conjunciones que piden INDICATIVO", "body": "Otras conjunciones presentan hechos constatados —causa, tiempo real, concesión real— y van con indicativo. Aquí el italiano se separa del español: «aunque llueva» es «anche se piove». Solo en el período hipotético aparece el congiuntivo: «anche se piovesse, usciremmo lo stesso».", "bullets": ["Concesión real: anche se + indicativo («anche se piove»).", "Causa: siccome, poiché, dato che, perché causal.", "Tiempo: mentre, dopo che, appena, da quando.", "«Dopo che è arrivato», no «dopo che sia arrivato»."]}, {"heading": "Conectores del discurso: enlazar ideas", "body": "Los conectores no son conjunciones: no rigen ningún modo y unen frases independientes, tras punto, punto y coma o coma. Algunos, como «quindi» o «invece», también van dentro de la frase: «Ho quindi deciso di restare». Elige según la relación que quieras marcar.", "bullets": ["Consecuencia: quindi, dunque, perciò, di conseguenza.", "Oposición: tuttavia, però, eppure. Contraste: invece, al contrario.", "Adición: inoltre, in più. Concesión: comunque, in ogni caso.", "«Comunque» significa «de todos modos», no «como quiera»."]}]'::jsonb, '[{"it": "Benché sia stanco, continua a lavorare.", "es": "Aunque está cansado, sigue trabajando.", "text": "Benché sia stanco, continua a lavorare.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f2dd5a81-980b-51e6-aba3-c8faa003fdd7.mp3"}, {"it": "Anche se piove, usciamo lo stesso.", "es": "Aunque llueve, salimos igual.", "text": "Anche se piove, usciamo lo stesso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/40f7e059-d5dd-5c3a-ab1d-7a32675136f1.mp3"}, {"it": "Sbrigati, prima che il negozio chiuda!", "es": "¡Date prisa, antes de que la tienda cierre!", "text": "Sbrigati, prima che il negozio chiuda!", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0b5b51ff-e6d8-5aff-afe0-de24e0909fee.mp3"}, {"it": "È un ottimo ristorante; tuttavia, è un po'' caro.", "es": "Es un restaurante excelente; sin embargo, es un poco caro.", "text": "È un ottimo ristorante; tuttavia, è un po'' caro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/578fe684-9d17-5bf3-a524-04f79bbf6312.mp3"}]'::jsonb, '[{"title": "Un solo «aunque» español, dos italianos", "body": "El español «aunque» se reparte en dos. Si el hecho es real y constatado, «anche se» + indicativo: «anche se piove». Si marcas la concesión, «benché», «sebbene» o «nonostante» + congiuntivo: «benché piova». «Benché è tardi» es agramatical, por muy cierto que sea."}, {"title": "«prima che» o «prima di»: mira el sujeto", "body": "Con sujetos distintos, «prima che» + congiuntivo: «prima che tu parta». Con el mismo sujeto, el italiano prefiere preposición + infinitivo: «prima di uscire», «senza dire nulla», «per capire». Lo que no existe es «prima di esco» ni «prima che esco»."}, {"title": "«Tuttavia» no significa «todavía»", "body": "Los conectores no rigen modo: se eligen por la relación —consecuencia (quindi, di conseguenza), oposición (tuttavia, però), adición (inoltre)—. Y ojo con el parecido: «tuttavia» es «sin embargo»; «todavía» se dice «ancora»; «invece» es «en cambio»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Cuál de estas frases es correcta en italiano?", "options": ["Benché sia tardi, finisco il lavoro.", "Benché è tardi, finisco il lavoro.", "Benché era tardi, finisco il lavoro."], "answer": "Benché sia tardi, finisco il lavoro.", "id": "u23q1"}, {"type": "cloze", "prompt": "Completa con el verbo «capire» en la forma que exige «affinché». El sujeto es «tutti».", "text": "Parlo piano affinché tutti mi ___.", "answer": "capiscano", "accepted": ["capiscano"], "id": "u23q2"}, {"type": "multiple_choice", "prompt": "Los dos verbos tienen el mismo sujeto («io»). ¿Cuál es correcta?", "options": ["Prima di uscire, controllo sempre il gas.", "Prima che esco, controllo sempre il gas.", "Prima di che esco, controllo sempre il gas."], "answer": "Prima di uscire, controllo sempre il gas.", "id": "u23q3"}, {"type": "cloze", "prompt": "Completa con «piovere» en el modo que exige «anche se». La otra parte de la frase va en presente.", "text": "Anche se ___, usciamo lo stesso.", "answer": "piove", "accepted": ["piove"], "id": "u23q4"}, {"type": "multiple_choice", "prompt": "Elige el conector de CONSECUENCIA: «Il treno era in ritardo; ___ siamo arrivati tardi alla riunione.»", "options": ["di conseguenza", "tuttavia", "inoltre"], "answer": "di conseguenza", "id": "u23q5"}]'::jsonb)
